// effectiveStatus shows a monitor as down the instant its deadline+grace has
// passed, even before the once-a-minute sweeper commits the flip — so the
// dashboard never lags reality by up to a minute.
func effectiveStatus(h heartbeat.Heartbeat) heartbeat.Status {
	if h.Overdue(time.Now().UTC()) {
		return heartbeat.StatusDown
	}
	return h.Status
}

func lastPing(h heartbeat.Heartbeat) string {
	if h.LastPingAt == nil {
		return "never"
	}
	return h.LastPingAt.UTC().Format(time.RFC3339)
}

func nextDue(h heartbeat.Heartbeat) string {
	if h.Status == heartbeat.StatusPaused || h.ExpectedBy == nil {
		return "—"
	}
	return h.ExpectedBy.UTC().Format(time.RFC3339)
}

// pingURL builds the public ping URL. With an empty baseURL (dev) it falls
// back to a host-relative path so the page is still usable.
func pingURL(baseURL, token, action string) string {
	u := baseURL + "/ping/" + token
	if action != "" {
		u += "/" + action
	}
	return u
}

func curlExample(baseURL, token string) string {
	return "curl -fsS " + pingURL(baseURL, token, "")
}

func humanizeSeconds(secs int) string {
	d := time.Duration(secs) * time.Second
	switch {
	case secs == 0:
		return "none"
	case secs%86400 == 0:
		return plural(secs/86400, "day")
	case secs%3600 == 0:
		return plural(secs/3600, "hour")
	case secs%60 == 0:
		return plural(secs/60, "minute")
	default:
		return d.String()
	}
}

func plural(n int, unit string) string {
	s := strconv.Itoa(n) + " " + unit
	if n != 1 {
		s += "s"
	}
	return s
}

func orDefault(v, def string) string {
	if v == "" {
		return def
	}
	return v
}

func orDash(s string) string {
	if s == "" {
		return "—"
	}
	return s
}

